.settings-sidebar {
    width: 240px;
    min-height: 100%;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
    background-color: #f8f9fa;
}

.sidebar-title {
    padding: 0 1rem;
    margin-bottom: 1rem;
    font-weight: 600;
}

.settings-sidebar .nav-link {
    border-radius: 0;
    padding: 0.65rem 1rem;
    color: #495057;
    font-weight: 500;
    transition: background-color 0.15s;
}

.settings-sidebar .nav-link:hover:not(.active) {
    background-color: #e9ecef;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

@inject ISettingsService SettingsService

<div class="card">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => isExpanded = !isExpanded">
        <h6 class="mb-0">Change Password</h6>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </div>
    @if (isExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword"
                       class="form-control @(confirmMismatch ? "is-invalid" : "")" />
                @if (confirmMismatch)
                {
                    <div class="invalid-feedback">Passwords do not match.</div>
                }
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync"
                    disabled="@(!CanSubmit)">
                @if (submitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
            @if (message is not null)
            {
                <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3 mb-0">@message</div>
            }
        </div>
    }
</div>

@code {
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private bool isExpanded;
    private bool submitting;
    private string? message;
    private bool isError;

    private bool confirmMismatch =>
        confirmPassword.Length > 0 && confirmPassword != newPassword;

    private bool CanSubmit =>
        !submitting
        && currentPassword.Length > 0
        && newPassword.Length > 0
        && confirmPassword == newPassword;

    private async Task UpdatePasswordAsync()
    {
        submitting = true;
        message = null;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            message = "Password updated successfully!";
            isError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            message = $"Failed to update password: {ex.Message}";
            isError = true;
        }
        finally
        {
            submitting = false;
        }
    }
}

@if (Visible)
{
    <div class="modal-backdrop show" @onclick="Cancel"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@Session?.Device</strong> from <strong>@Session?.Location</strong>?
                    </p>
                    <p class="text-muted mb-0">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirmed { get; set; }
    [Parameter] public EventCallback OnCancelled { get; set; }

    private Task Confirm() => OnConfirmed.InvokeAsync();
    private Task Cancel() => OnCancelled.InvokeAsync();
}

