    <table class="table table-hover align-middle">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                var isCurrent = session.Id == CurrentSessionId;
                <tr>
                    <td>
                        @session.Device
                        @if (isCurrent)
                        {
                            <span class="badge bg-success ms-2">Current</span>
                        }
                    </td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td class="text-end">
                        @if (!isCurrent)
                        {
                            <button class="btn btn-outline-danger btn-sm"
                                    @onclick="() => ShowRevokeDialog(session)">
                                Revoke
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

<RevokeSessionDialog Visible="@(sessionToRevoke is not null)"
                     Session="@sessionToRevoke"
                     OnConfirmed="ConfirmRevoke"
                     OnCancelled="() => sessionToRevoke = null" />

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session) => sessionToRevoke = session;

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnSessionRevoked.InvokeAsync(sessionToRevoke.Id);
            sessionToRevoke = null;
        }
    }
}
