                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(selectedTheme == theme)"
                                   @onchange="() => selectedTheme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(selectedFontSize == size)"
                                   @onchange="() => selectedFontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="selectedLanguage">
                        @foreach (var lang in languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@compactMode" @onchange="e => compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top: 1rem;">
                <div class="card-header fw-semibold">Live Preview</div>
                <div class="card-body @PreviewClasses" style="@PreviewStyles">
                    <h6 style="@FontSizeStyle">Dashboard</h6>
                    <p style="@FontSizeStyle" class="@(compactMode ? "mb-1" : "mb-3")">
                        Welcome back! Here is how your interface looks with the current settings.
                    </p>
                    <div class="d-flex gap-2 @(compactMode ? "mb-1" : "mb-3")">
                        <span class="badge bg-primary" style="@FontSizeStyle">Active</span>
                        <span class="badge bg-secondary" style="@FontSizeStyle">Pending</span>
                    </div>
                    <button class="btn btn-sm @(selectedTheme == "Dark" ? "btn-light" : "btn-primary")"
                            style="@FontSizeStyle" disabled>
                        Sample Button
                    </button>
                    <div class="mt-2">
                        <small class="@(selectedTheme == "Dark" ? "text-light" : "text-muted")" style="@FontSizeStyle">
                            Theme: @selectedTheme · Font: @selectedFontSize · Lang: @selectedLanguage · Compact: @(compactMode ? "On" : "Off")
                        </small>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @if (saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save
    </button>

    @if (toastMessage is not null)
    {
        <div class="alert alert-success mt-3 alert-dismissible fade show" role="alert">
            @toastMessage
            <button type="button" class="btn-close" @onclick="() => toastMessage = null"></button>
        </div>
    }
}

@code {
    private string selectedTheme = "Light";
    private string selectedFontSize = "Medium";
    private string selectedLanguage = "English";
    private bool compactMode;
    private bool loading = true;
    private bool saving;
    private string? toastMessage;

    private static readonly string[] languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese", "Korean"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        selectedTheme = settings.Theme;
        selectedFontSize = settings.FontSize;
        selectedLanguage = settings.Language;
        compactMode = settings.CompactMode;
        loading = false;
    }

    private string PreviewClasses => selectedTheme == "Dark"
        ? "text-light" : "";

    private string PreviewStyles => selectedTheme == "Dark"
        ? "background-color:#1a1a2e;color:#e0e0e0;transition:all .3s"
        : "background-color:#ffffff;color:#212529;transition:all .3s";

    private string FontSizeStyle => selectedFontSize switch
    {
        "Small" => "font-size:0.8rem",
        "Large" => "font-size:1.2rem",
        _ => "font-size:1rem"
    };

    private async Task SaveAsync()
    {
        saving = true;
        var updated = new AppearanceSettings(selectedTheme, selectedFontSize, selectedLanguage, compactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        toastMessage = "Appearance settings saved!";
        saving = false;
    }
}

