                                 CurrentSessionId="@currentSessionId"
                                 OnSessionRevoked="RevokeSessionAsync" />
        </div>
    </div>
}

@code {
    private SecuritySettings? settings;
    private bool twoFactorEnabled;
    private string? currentSessionId;
    private bool loading = true;

    protected override async Task OnInitializedAsync()
    {
        settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        // Treat the most recently active session as the current one
        currentSessionId = settings.Sessions
            .OrderByDescending(s => s.LastActive)
            .FirstOrDefault()?.Id;
        loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        settings = await SettingsService.GetSecuritySettingsAsync();
    }
}
