@inject ISettingsService SettingsService

<h3 class="mb-4">Profile</h3>

@if (loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading...</span></div>
    </div>
}
else if (profile is not null)
{
    <div class="row g-4">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="editName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="editEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="editBio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="text-center p-3 border rounded bg-light">
                <img src="@profile.AvatarUrl" alt="Avatar"
                     class="rounded-circle mb-2"
                     style="width:120px;height:120px;object-fit:cover;"
                     @onerror="@(() => {})" />
                <div class="small text-muted text-break mt-2">@profile.AvatarUrl</div>
            </div>
        </div>
    </div>

    <div class="mt-4 d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @if (saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
            Discard Changes
        </button>
    </div>

    @if (toastMessage is not null)
    {
        <div class="alert alert-success mt-3 alert-dismissible fade show" role="alert">
            @toastMessage
            <button type="button" class="btn-close" @onclick="() => toastMessage = null"></button>
        </div>
    }
}

@code {
    private UserProfile? profile;
    private string editName = "";
    private string editEmail = "";
    private string editBio = "";
    private bool loading = true;
    private bool saving;
    private string? toastMessage;

    protected override async Task OnInitializedAsync()
    {
        profile = await SettingsService.GetProfileAsync();
        ResetFields();
        loading = false;
    }

    private void ResetFields()
    {
        if (profile is null) return;
        editName = profile.DisplayName;
        editEmail = profile.Email;
        editBio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        if (profile is null) return;
        saving = true;
        var updated = profile with { DisplayName = editName, Email = editEmail, Bio = editBio };
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
        toastMessage = "Profile saved successfully!";
        saving = false;
    }

    private void Discard()
    {
        ResetFields();
        toastMessage = null;
    }
}

