@inject ISettingsService SettingsService

<h3 class="mb-4">Security</h3>

@if (loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading...</span></div>
    </div>
}
else if (settings is not null)
{
    <div class="mb-4">
        <ChangePasswordPanel />
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch mb-0">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@twoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        Two-Factor Authentication
                    </label>
                </div>
                @if (twoFactorEnabled)
                {
                    <span class="badge bg-success">Enabled</span>
                }
                else
                {
                    <span class="badge bg-warning text-dark">Disabled</span>
                }
            </div>
            @if (settings.LastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    <div class="card">
        <div class="card-body">
            <h6 class="card-title mb-3">Active Sessions</h6>
            <ActiveSessionsTable Sessions="@settings.Sessions.ToList()"
                                 CurrentSessionId="@currentSessionId"
                                 OnSessionRevoked="RevokeSessionAsync" />
        </div>
    </div>
}

@code {
    private SecuritySettings? settings;
    private bool twoFactorEnabled;
    private string? currentSessionId;
    private bool loading = true;

    protected override async Task OnInitializedAsync()
    {
        settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        // Treat the most recently active session as the current one
        currentSessionId = settings.Sessions
            .OrderByDescending(s => s.LastActive)
            .FirstOrDefault()?.Id;
        loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        settings = await SettingsService.GetSecuritySettingsAsync();
    }
}

